settings._cssCustom:
/* ============================================================================
   Ampy — mini-menu (block 2) · _cssCustom
   Scoped under .ampy-mm so it is safe to paste anywhere (no global leakage).
   Tokens are declared as scoped fallbacks on .ampy-mm — if the Ampy Bricks theme
   already exposes the ap* custom properties globally, these simply mirror them
   (identical values), so the block renders the same with or without the theme layer.
   Everything below is byte-for-byte the design that was rendered and signed off.
   ============================================================================ */
.ampy-mm{
  /* — token fallbacks (mirror ampy-design-system/reference/tokens.css) — */
  --ap-teal:#00a991; --ap-teal-bright:#1cc4af;
  --bg-surface:#ffffff;
  --ink:#0f123c; --ink-muted:#565e82;
  --line:rgba(15,18,60,0.10); --line-strong:rgba(15,18,60,0.16);
  --font:"Outfit",system-ui,-apple-system,sans-serif;
  --w-reg:400; --w-light:300; --w-semi:600; --w-bold:700; --w-black:800;
  --fs-eyebrow:clamp(1.2rem,1.1rem + 0.2vw,1.35rem);
  --fs-sm:clamp(1.4rem,1.3rem + 0.3vw,1.6rem);
  --fs-lead:clamp(1.9rem,1.7rem + 0.6vw,2.3rem);
  --fs-h3:clamp(2.2rem,1.9rem + 0.9vw,2.8rem);
  --fs-h2:clamp(3.0rem,2.4rem + 1.8vw,4.4rem);
  --lh-tight:1.04; --lh-snug:1.18; --tr-tight:-0.022em; --tr-eyebrow:0.16em;
  --s-2:0.8rem; --s-3:1.2rem; --s-4:1.6rem; --s-5:2.4rem; --s-6:3.2rem;
  --s-7:4.8rem; --s-8:6.4rem; --s-9:9.6rem;
  --r-md:1.4rem; --r-lg:2.2rem;
  --shadow-2:0 0.6rem 1.6rem -0.4rem rgba(15,18,60,0.10),0 0.2rem 0.6rem rgba(15,18,60,0.06);
  --shadow-3:0 2.4rem 5rem -1rem rgba(15,18,60,0.18),0 0.8rem 1.6rem -0.6rem rgba(15,18,60,0.10);
  --shadow-teal:0 1.2rem 3rem -0.8rem rgba(0,169,145,0.45);
  --ring:0 0 0 0.3rem rgba(0,169,145,0.28);
  --fast:140ms; --normal:280ms; --slow:520ms;
  --ease:cubic-bezier(0.2,0.6,0.2,1); --ease-out:cubic-bezier(0.16,1,0.3,1);
  --container:120rem;

  font-family:var(--font);color:var(--ink);
  padding-block:clamp(var(--s-8),4rem + 4vw,9rem);
}
.ampy-mm *,.ampy-mm *::before,.ampy-mm *::after{box-sizing:border-box;}
.ampy-mm .mm__wrap{width:100%;max-width:var(--container);margin-inline:auto;padding-inline:var(--s-5);}
.ampy-mm .mm__head{max-width:60rem;}

/* — eyebrow — */
.ampy-mm .eyebrow{display:inline-flex;align-items:center;gap:var(--s-2);
  font-size:var(--fs-eyebrow);font-weight:var(--w-semi);letter-spacing:var(--tr-eyebrow);
  text-transform:uppercase;color:var(--ap-teal);}
.ampy-mm .eyebrow::before{content:"";width:2.4rem;height:0.2rem;border-radius:2px;background:var(--ap-teal);}

/* — head type — */
.ampy-mm .mm__title{font-size:var(--fs-h2);font-weight:var(--w-black);line-height:var(--lh-snug);
  letter-spacing:var(--tr-tight);color:var(--ink);margin-top:var(--s-4);max-width:20ch;}
.ampy-mm .mm__lead{font-size:var(--fs-lead);font-weight:var(--w-light);line-height:1.45;
  color:var(--ink-muted);margin-top:var(--s-4);max-width:52ch;}

/* — grid (semantic list) — */
.ampy-mm .mm__grid{list-style:none;margin:var(--s-8) 0 0;padding:0;
  display:grid;grid-template-columns:repeat(3,1fr);gap:var(--s-5);}
.ampy-mm .mm__grid > li{display:flex;margin:0;padding:0;}

/* — the glass card (whole card is the link) — */
.ampy-mm .mm-card{position:relative;width:100%;display:flex;flex-direction:column;overflow:hidden;
  text-decoration:none;color:inherit;
  background:var(--bg-surface);border:0.1rem solid var(--line);border-radius:var(--r-lg);
  box-shadow:var(--shadow-2);padding:clamp(var(--s-6),2rem + 1.4vw,3.6rem);
  transition:transform var(--fast) var(--ease),box-shadow var(--normal) var(--ease),
    border-color var(--normal) var(--ease);isolation:isolate;}
/* SIGNATURE: the teal top-edge that draws across on hover */
.ampy-mm .mm-card::before{content:"";position:absolute;top:0;left:0;right:0;height:0.4rem;
  background:linear-gradient(90deg,var(--ap-teal),var(--ap-teal-bright));
  transform:scaleX(0);transform-origin:left center;
  transition:transform var(--normal) var(--ease-out);border-radius:0 0 2px 2px;z-index:2;}
.ampy-mm .mm-card:hover,.ampy-mm .mm-card:focus-visible{transform:translateY(-0.4rem);
  box-shadow:var(--shadow-3),var(--shadow-teal);border-color:var(--line-strong);outline:0;}
.ampy-mm .mm-card:hover::before,.ampy-mm .mm-card:focus-visible::before{transform:scaleX(1);}
.ampy-mm .mm-card:focus-visible{box-shadow:var(--ring),var(--shadow-3);}
.ampy-mm .mm-card:active{transform:translateY(-0.1rem);transition-duration:var(--fast);}
@media (forced-colors:active){
  .ampy-mm .mm-card:focus-visible{outline:0.2rem solid;outline-offset:0.2rem;}
}

/* — glyph tile — */
.ampy-mm .mm-card__glyph{display:inline-flex;align-items:center;justify-content:center;
  width:6.4rem;height:6.4rem;border-radius:var(--r-md);color:var(--ap-teal);
  background:rgba(0,169,145,0.10);box-shadow:inset 0 0 0 0.1rem rgba(0,169,145,0.16);
  transition:background var(--normal) var(--ease);}
.ampy-mm .mm-card__glyph svg{display:block;width:3rem;height:3rem;fill:none;stroke:currentColor;
  stroke-width:1.75;stroke-linecap:round;stroke-linejoin:round;}
.ampy-mm .mm-card:hover .mm-card__glyph,
.ampy-mm .mm-card:focus-visible .mm-card__glyph{background:rgba(0,169,145,0.16);}

/* — text — */
.ampy-mm .mm-card__title{font-size:var(--fs-h3);font-weight:var(--w-bold);line-height:var(--lh-tight);
  letter-spacing:var(--tr-tight);color:var(--ink);margin-top:var(--s-5);}
.ampy-mm .mm-card__desc{font-size:var(--fs-sm);font-weight:var(--w-reg);line-height:1.5;
  color:var(--ink-muted);margin-top:var(--s-3);max-width:32ch;}

/* — link affordance (navy label for AA contrast, teal arrow) — */
.ampy-mm .mm-card__link{display:inline-flex;align-items:center;gap:var(--s-2);
  margin-top:auto;padding-top:var(--s-5);
  font-size:var(--fs-sm);font-weight:var(--w-semi);color:var(--ink);
  transition:color var(--fast) var(--ease);}
.ampy-mm .mm-card__link .arrow{display:inline-flex;color:var(--ap-teal);
  transition:transform var(--fast) var(--ease),color var(--fast) var(--ease);}
.ampy-mm .mm-card__link .arrow svg{display:block;width:1.8rem;height:1.8rem;fill:none;stroke:currentColor;
  stroke-width:2;stroke-linecap:round;stroke-linejoin:round;}
.ampy-mm .mm-card:hover .mm-card__link .arrow,
.ampy-mm .mm-card:focus-visible .mm-card__link .arrow{transform:translateX(0.4rem);color:var(--ap-teal-bright);}

/* — quiet fade-up on load — */
@keyframes ampy-mm-rise{from{opacity:0;transform:translateY(1.6rem);}to{opacity:1;transform:none;}}
.ampy-mm .rise{animation:ampy-mm-rise var(--slow) var(--ease-out) both;}
.ampy-mm .rise.d1{animation-delay:0.06s;} .ampy-mm .rise.d2{animation-delay:0.14s;}
.ampy-mm .rise.d3{animation-delay:0.22s;} .ampy-mm .rise.d4{animation-delay:0.30s;}

/* ============================================================================
   Responsive — elegant reflow (not just stacked full-width blocks)
   ============================================================================ */
@media (min-width:881px){
  .ampy-mm .mm-card__body{display:contents;}
}
@media (max-width:880px){
  .ampy-mm .mm__grid{grid-template-columns:1fr;gap:var(--s-4);margin-top:var(--s-7);}
  .ampy-mm .mm-card{flex-direction:row;align-items:flex-start;gap:var(--s-5);
    padding:clamp(var(--s-5),1.4rem + 2vw,var(--s-6));}
  .ampy-mm .mm-card__glyph{flex:0 0 auto;width:5.6rem;height:5.6rem;margin-top:0.2rem;}
  .ampy-mm .mm-card__body{display:flex;flex-direction:column;min-width:0;}
  .ampy-mm .mm-card__title{font-size:var(--fs-lead);margin-top:0;}
  .ampy-mm .mm-card__desc{margin-top:var(--s-2);max-width:42ch;}
  .ampy-mm .mm-card__link{margin-top:var(--s-4);padding-top:0;}
  .ampy-mm .mm-card::before{top:0;bottom:0;right:auto;width:0.4rem;height:auto;
    transform:scaleY(0);transform-origin:top center;border-radius:0 2px 2px 0;}
  .ampy-mm .mm-card:hover::before,.ampy-mm .mm-card:focus-visible::before{transform:scaleY(1);}
}
@media (max-width:420px){
  .ampy-mm .mm-card{flex-direction:column;align-items:flex-start;gap:0;}
  .ampy-mm .mm-card__title{margin-top:var(--s-5);}
  .ampy-mm .mm-card__desc{max-width:36ch;}
  .ampy-mm .mm-card__link{margin-top:var(--s-4);}
  .ampy-mm .mm-card::before{top:0;left:0;right:0;bottom:auto;width:auto;height:0.4rem;
    transform:scaleX(0);transform-origin:left center;border-radius:0 0 2px 2px;}
  .ampy-mm .mm-card:hover::before,.ampy-mm .mm-card:focus-visible::before{transform:scaleX(1);}
}
@media (prefers-reduced-motion:reduce){
  .ampy-mm *{animation:none !important;transition:none !important;}
}
